SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION f_get_transbank_data_code ( as_code char ) RETURNS varchar AS $body$
DECLARE

    ls_desc varchar(50);

BEGIN

    if as_code = 'LON' then
        ls_desc := 'เงินกู้';
    elsif as_code = 'MRT' then
        ls_desc := 'เงินรอจ่ายคืน';
    elsif as_code = 'DEP' then
        ls_desc := 'เงินฝาก';
    elsif as_code = 'DIV' then
        ls_desc := 'ปันผล';
    else
        ls_desc := '';
    end if;


  RETURN trim(both ls_desc);

  
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
